def extract_text(image_path: str) -> str:
    image = cv2.imread(image_path)
    return pytesseract.image_to_string(image)

def process_document(image_path: str, inventory_db) -> dict:
    extracted = ocr_and_extract(image_path)
    for item in extracted['items']:
        inventory_db.update(item['name'], item['quantity'])
    return {'status': 'updated', 'items': len(extracted['items'])}
